        <td>Monday</td>
        <td>Tuesday</td>
        <td>Thursday</td>
        <td>Friday</td>
        <td>Saturday</td>
      </thead>
      <tbody>
        <td>9-5</td>
        <td>9-5</td>
        <td>9-5</td>
        <td>9-5</td>
        <td>9-5</td>
        <td>9-5</td>
        <td>9-5</td>
      </tbody>

    </table>
    </>

  );
}

export default App;
